#include <bits/stdc++.h>
using namespace std;

int calculateMinimumCutCost(int stickLength, vector<int>& cutPositions) {

    // Step 1: Add boundaries
    vector<int> cuts;
    cuts.push_back(0);

    for (int cut : cutPositions)
        cuts.push_back(cut);

    cuts.push_back(stickLength);

    // Step 2: Sort cuts
    sort(cuts.begin(), cuts.end());

    int n = cuts.size();

    // Step 3: DP table
    vector<vector<int>> dp(n, vector<int>(n, 0));

    // Step 4: Interval DP
    for (int length = 2; length < n; length++) {

        for (int i = 0; i + length < n; i++) {

            int j = i + length;

            dp[i][j] = INT_MAX;

            for (int k = i + 1; k < j; k++) {

                int cost = dp[i][k]
                         + dp[k][j]
                         + (cuts[j] - cuts[i]);

                dp[i][j] = min(dp[i][j], cost);
            }

            // If no cut possible inside interval
            if (dp[i][j] == INT_MAX)
                dp[i][j] = 0;
        }
    }

    return dp[0][n - 1];
}

