def calculateMinimumCutCost(stickLength, cutPositions):
    cutPositions = [0] + sorted(cutPositions) + [stickLength]
    m = len(cutPositions)
    dp = [[0] * m for _ in range(m)]
    for length in range(2, m):
        for left in range(m - length):
            right = left + length
            dp[left][right] = min(dp[left][k] + dp[k][right] for k in range(left + 1, right)) + cutPositions[right] - cutPositions[left]
    return dp[0][m - 1]

