#include <stdio.h>
#include <stdlib.h>
#include <limits.h>

int compare(const void* a, const void* b) {
    return (*(int*)a - *(int*)b);
}

int calculateMinimumCutCost(int stickLength, int* cutPositions, int numberOfCuts) {

    // Step 1: Create cuts array with boundaries
    int n = numberOfCuts + 2;
    int* cuts = (int*)malloc(n * sizeof(int));

    cuts[0] = 0;
    for (int i = 0; i < numberOfCuts; i++)
        cuts[i + 1] = cutPositions[i];
    cuts[n - 1] = stickLength;

    // Step 2: Sort cuts
    qsort(cuts, n, sizeof(int), compare);

    // Step 3: DP table
    int** dp = (int**)malloc(n * sizeof(int*));
    for (int i = 0; i < n; i++) {
        dp[i] = (int*)calloc(n, sizeof(int));
    }

    // Step 4: Interval DP
    for (int length = 2; length < n; length++) {

        for (int i = 0; i + length < n; i++) {

            int j = i + length;
            dp[i][j] = INT_MAX;

            for (int k = i + 1; k < j; k++) {

                int cost = dp[i][k]
                         + dp[k][j]
                         + (cuts[j] - cuts[i]);

                if (cost < dp[i][j])
                    dp[i][j] = cost;
            }

            // No cut inside interval
            if (dp[i][j] == INT_MAX)
                dp[i][j] = 0;
        }
    }

    int result = dp[0][n - 1];

    // Step 5: Free memory
    for (int i = 0; i < n; i++)
        free(dp[i]);
    free(dp);
    free(cuts);

    return result;
}

