function calculateMinimumCutCost(stickLength, cutPositions) {
    cutPositions.push(0, stickLength);
    cutPositions.sort((a, b) => a - b);
    const m = cutPositions.length;
    const dp = Array.from({ length: m }, () => Array(m).fill(0));
    for (let length = 2; length < m; length++) {
        for (let left = 0; left + length < m; left++) {
            const right = left + length;
            let calculateMinimumCutCost = Infinity;
            for (let mid = left + 1; mid < right; mid++) {
                const cost = dp[left][mid] + dp[mid][right] + cutPositions[right] - cutPositions[left];
                if (cost < calculateMinimumCutCost) calculateMinimumCutCost = cost;
            }
            dp[left][right] = calculateMinimumCutCost === Infinity ? 0 : calculateMinimumCutCost;
        }
    }
    return dp[0][m - 1];
}
module.exports = calculateMinimumCutCost;
